package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testWithIgnoreSurroundingSpaces() throws Exception {
        // Given
        CSVFormat spyFormat = spy(csvFormat);

        // When
        CSVFormat result = spyFormat.withIgnoreSurroundingSpaces();

        // Then
        assertTrue(result.getIgnoreSurroundingSpaces());
        verify(spyFormat, times(1)).withIgnoreSurroundingSpaces(true);
    }

